// WF03 Prospector v3.0 — Parse Input
// Soporta 3 formatos de input + job_titles custom
const raw = $input.all()[0].json;
const body = raw.body || raw;

let empresas = [];

if (body.empresas && Array.isArray(body.empresas)) {
  empresas = body.empresas.map(e => {
    const base = typeof e === 'string' ? {
      empresa: e,
      pais: body.pais || 'Colombia',
      paises: body.paises || [],
      linea_negocio: body.linea || body.linea_negocio || 'Intralogística',
      tier: body.tier || 'MONITOREO',
      company_domain: body.company_domain || '',
    } : e;
    return { ...base, _custom_titles: body.job_titles || [] };
  });
} else if (body.empresa || body['COMPANY NAME']) {
  empresas = [{ ...body, _custom_titles: body.job_titles || [] }];
}

if (!empresas.length) throw new Error('WF03: No empresas encontradas.');

return empresas.flatMap(e => {
  const tier = (e.tier_calculado || e.tier || e['TIER'] || 'MONITOREO').toUpperCase();
  const maxContacts = tier === 'ORO' ? 5 : tier === 'PLATA' ? 4 : tier === 'MONITOREO' ? 3 : 0;
  if (maxContacts === 0) return [];

  const empresa   = e.empresa || e.company_name || e['COMPANY NAME'] || '';
  const paisBase  = e.pais || e['PAÍS'] || 'Colombia';
  const linea     = e.linea_negocio || e.linea || e['LÍNEA DE NEGOCIO'] || '';
  const domain    = e.company_domain || e['DOMINIO'] || '';
  const fecha     = new Date().toISOString().split('T')[0];
  const paises    = (e.paises && e.paises.length > 0) ? e.paises : [paisBase];

  return paises.map(pais => ({ json: {
    empresa, pais, linea_negocio: linea, tier,
    company_domain: domain,
    score_calificacion: e.score_calificacion || 0,
    score_radar: e.score_radar || 0,
    composite_score: e.composite_score || 0,
    max_contacts: maxContacts,
    fecha_prospeccion: fecha,
    grupo_empresarial: e.grupo_empresarial || '',
    es_multinacional: paises.length > 1,
    _custom_titles: e._custom_titles || [],
  }}));
}).filter(Boolean);

const e = $input.all()[0].json;
const linea = (e.linea_negocio || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');

const TITLES = {
  BHS: ['Chief Executive Officer','CEO','Chief Operating Officer','COO','Director General Aeropuerto','Director de Infraestructura Aeropuerto','Director de Operaciones Aeropuerto','VP Airport Operations','Airport Operations Manager','BHS Manager','Baggage Handling System Manager','Cargo Terminal Manager','Gerente de Infraestructura Aeropuerto','Gerente de Operaciones Aeropuerto','Managing Director','Country Manager'],
  CARTON_PAPEL: ['Gerente General','Director General','Director de Proyectos','Director Técnico','Director de Compras','Director de Operaciones','Gerente de Planta','Gerente de Mantenimiento','Project Manager','Gerente de Proyectos','Plant Manager','Manufacturing Director'],
  INTRALOGISTICA: ['Chief Operations Officer','COO','CEO','VP Operations','Operations Director','Plant Director','Manufacturing Director','Supply Chain Director','Director de Operaciones','Director de Planta','Director de Manufactura','Operations Manager','Plant Manager','Manufacturing Manager','Supply Chain Manager','Logistics Manager','Gerente de Planta','Gerente de Operaciones','Gerente de Producción','Gerente de Logística','Gerente de Supply Chain','Gerente General','Country Manager','Managing Director'],
  FINAL_LINEA: ['CEO','COO','Gerente General','Director General','Director de Operaciones','Director de Supply Chain','Director de Manufactura','Director de Producción','Plant Manager','Gerente de Planta','Operations Manager','Supply Chain Manager','Gerente de Supply Chain','Logistics Manager','Head of Operations','Country Manager'],
  MOTOS: ['CEO','Gerente General','Director General','Director de Manufactura','Director de Operaciones','Plant Manager','Gerente de Planta','Manufacturing Manager','Production Manager','Assembly Manager','Operations Manager'],
  SOLUMAT: ['CEO','Gerente General','Director General','Director de Operaciones','Director de Manufactura','Plant Manager','Gerente de Planta','Manufacturing Manager','Process Manager','Operations Manager','Production Manager']
};

let lineaKey = 'INTRALOGISTICA';
if (linea.includes('bhs') || linea.includes('aeropuerto') || linea.includes('cargo') || linea.includes('uld')) lineaKey = 'BHS';
else if (linea.includes('cart') || linea.includes('corrugado') || linea.includes('papel')) lineaKey = 'CARTON_PAPEL';
else if (linea.includes('final') || linea.includes('alimento') || linea.includes('bebida')) lineaKey = 'FINAL_LINEA';
else if (linea.includes('moto')) lineaKey = 'MOTOS';
else if (linea.includes('solumat') || linea.includes('plastico')) lineaKey = 'SOLUMAT';

// Usar job_titles custom si vienen en el input, si no, usar los de la línea
const customTitles = e._custom_titles || [];
const titles = customTitles.length > 0 ? customTitles : (TITLES[lineaKey] || TITLES.INTRALOGISTICA);
const perPage = Math.min(25, (e.max_contacts || 3) * 4);

const searchBody = {
  page: 1, per_page: perPage,
  person_seniorities: ['c_suite', 'vp', 'director', 'manager'],
  person_titles: titles,
};

if (e.company_domain) searchBody.q_organization_domains_list = [e.company_domain];
else searchBody.q_organization_name = e.empresa;

const COUNTRY_MAP = { 'colombia':'Colombia','mexico':'Mexico','chile':'Chile','peru':'Peru','argentina':'Argentina','brasil':'Brazil','brazil':'Brazil','guatemala':'Guatemala','costa rica':'Costa Rica','ecuador':'Ecuador','panama':'Panama' };
const paisNorm = (e.pais || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'');
const countryMapped = COUNTRY_MAP[paisNorm] || e.pais;
if (countryMapped) searchBody.person_locations = [countryMapped];

return [{ json: { ...e, apollo_search_body: searchBody, _linea_key: lineaKey } }];

const apolloResp = $input.all()[0].json;
const ctx = $('Code: Build Apollo Query').first().json;
const statusCode = apolloResp.statusCode || apolloResp.status || 200;
if (statusCode === 429) return [{ json: { ...ctx, apollo_response: null, _rate_limited: true } }];
return [{ json: { ...ctx, apollo_response: apolloResp, _rate_limited: false } }];

const ctx = $input.all()[0].json;
const resp = ctx.apollo_response || {};
const raw  = resp.people || resp.contacts || resp.results || resp.data || [];
const maxContacts = ctx.max_contacts || 3;

function classifyNivel(title, seniority) {
  const t = (title || '').toLowerCase(), s = (seniority || '').toLowerCase();
  const cl = ['chief executive','chief operations','chief operating','gerente general','director general','managing director','country general manager','country manager','general manager'];
  if (cl.some(x => t.includes(x))) return 'C-LEVEL';
  if (t.startsWith('ceo') || t.includes(' ceo') || t.startsWith('coo') || t.includes(' coo') || s === 'c_suite') return 'C-LEVEL';
  if (t.includes('director') || t.includes('vice president') || t.includes(' vp ') || s === 'vp') return 'DIRECTOR';
  if (t.includes('gerente') || t.includes('manager') || t.includes('head of') || s === 'director' || s === 'manager') return 'GERENTE';
  return 'JEFE';
}

const NIVEL_ORDER = { 'C-LEVEL': 4, 'DIRECTOR': 3, 'GERENTE': 2, 'JEFE': 1 };

const scored = raw.map(p => {
  const nivel = classifyNivel(p.title, p.seniority);
  return { ...p, _nivel: nivel, _priority: (NIVEL_ORDER[nivel] || 0) * 10 + (p.email || p.has_email ? 3 : 0) + (p.linkedin_url ? 1 : 0) };
}).sort((a, b) => b._priority - a._priority);

const selected = scored.slice(0, maxContacts);
if (!selected.length) return [{ json: { ...ctx, contacts_found: 0, contacts: [], prospection_status: 'NO_CONTACTS_FOUND' } }];

const contacts = selected.map(p => {
  const phones = p.phone_numbers || [];
  return {
    nombre: p.first_name || '',
    apellido: p.last_name || p.last_name_obfuscated || '',
    cargo: p.title || '',
    nivel: p._nivel,
    email: p.email || p.work_email || '',
    email_status: p.email_status || (p.email ? 'verified' : (p.has_email ? 'available' : 'not_found')),
    linkedin: p.linkedin_url || '',
    tel_empresa: (p.organization && (p.organization.phone || (p.organization.primary_phone && p.organization.primary_phone.number))) || '',
    tel_movil: (phones.find(t => t.type === 'mobile') || {}).sanitized_number || '',
    tel_directo: (phones.find(t => t.type === 'work_direct' || t.type === 'direct') || {}).sanitized_number || '',
    grupo: (p.organization && p.organization.parent_organization && p.organization.parent_organization.name) || ctx.grupo_empresarial || '',
    ciudad: p.city || '',
    apollo_id: p.id || '',
    has_email: !!(p.email || p.has_email),
    has_linkedin: !!(p.linkedin_url),
  };
});

return [{ json: { ...ctx, contacts_found: contacts.length, contacts, prospection_status: 'CONTACTS_FOUND' } }];

// Fase 2: Enriquecer email/LinkedIn para C-LEVEL y DIRECTOR
const data = $input.all()[0].json;
const contacts = data.contacts || [];

// Solo enriquecer C-LEVEL y DIRECTOR (los que más importan)
const toEnrich = contacts.filter(c => c.nivel === 'C-LEVEL' || c.nivel === 'DIRECTOR');

if (!toEnrich.length) {
  // No hay C-Level/Director — saltar Fase 2
  return [{ json: { ...data, _skip_fase2: true } }];
}

// Construir array details para bulk_match (máx 10)
const details = toEnrich.slice(0, 10).map(c => ({
  id: c.apollo_id,
  first_name: c.nombre,
  last_name: c.apellido.replace(/\*+/g,'').trim(),
  organization_name: data.empresa,
  domain: data.company_domain || '',
}));

return [{ json: { ...data, _fase2_details: details, _skip_fase2: false } }];

// Mergear datos de Fase 2 en los contactos
const fase2Resp = $input.all()[0].json;
const ctx = $('Code: Prepare Fase 2').first().json;
const contacts = ctx.contacts || [];

const enriched = fase2Resp.matches || fase2Resp.people || fase2Resp.results || [];
const enrichMap = {};
for (const p of enriched) {
  if (p.id) enrichMap[p.id] = p;
}

const updatedContacts = contacts.map(c => {
  const match = enrichMap[c.apollo_id];
  if (!match) return c;
  return {
    ...c,
    email: match.email || match.work_email || c.email || '',
    email_status: match.email_status || c.email_status,
    linkedin: match.linkedin_url || c.linkedin || '',
    has_email: !!(match.email || match.work_email || c.email),
    has_linkedin: !!(match.linkedin_url || c.linkedin),
    fase2_done: true,
  };
});

return [{ json: { ...ctx, contacts: updatedContacts, _fase2_applied: true } }];

// Expandir contactos a filas + generar IDs + preparar para Supabase
const data = $input.all()[0].json;
const contacts = data.contacts || [];

return contacts.map((c, idx) => {
  const empShort = (data.empresa || '').substring(0, 20).replace(/\s+/g, '-').toUpperCase();
  const paisShort = (data.pais || '').substring(0, 3).toUpperCase();
  const id = `${empShort}-${paisShort}-${String(idx + 1).padStart(3, '0')}`;
  return { json: {
    ID:               id,
    Empresa:          data.empresa,
    Pais:             data.pais,
    Nombre:           c.nombre,
    Apellido:         c.apellido,
    Cargo:            c.cargo,
    Nivel:            c.nivel,
    Email_Verificado: c.email || '',
    Estado_Email:     c.email_status || '',
    LinkedIn:         c.linkedin || '',
    Tel_Empresa:      c.tel_empresa || '',
    Tel_Directo:      c.tel_directo || '',
    Tel_Movil:        c.tel_movil || '',
    Grupo:            c.grupo || '',
    Ciudad:           c.ciudad || '',
    Persona_ID:       c.apollo_id || '',
    Fecha:            data.fecha_prospeccion,
    Linea_Negocio:    data.linea_negocio,
    Tier:             data.tier,
    Es_Multinacional: data.es_multinacional ? 'Si' : 'No',
    Score_Cal:        data.score_calificacion || 0,
    Score_Radar:      data.score_radar || 0,
    Composite_Score:  data.composite_score || 0,
    _empresa_original: data.empresa,
    _pais_original:    data.pais,
  }};
});

// Upsert en Supabase — matec_radar.contactos
// Un DO block por lote de contactos de la misma empresa
const items = $input.all();
if (!items.length) return [];

const fecha = new Date().toISOString();

// Construir INSERT statements para cada contacto
const rows = items.map(item => {
  const d = item.json;
  const esc = v => (v || '').replace(/'/g, "''");
  return `(
    '${esc(d.Persona_ID)}',
    '${esc(d.Empresa)}',
    '${esc(d.Pais)}',
    '${esc(d.Nombre)}',
    '${esc(d.Apellido)}',
    '${esc(d.Cargo)}',
    '${esc(d.Nivel)}',
    '${esc(d.Email_Verificado)}',
    '${esc(d.Estado_Email)}',
    '${esc(d.LinkedIn)}',
    '${esc(d.Tel_Empresa)}',
    '${esc(d.Tel_Movil)}',
    '${esc(d.Linea_Negocio)}',
    '${esc(d.Tier)}',
    '${esc(d.Grupo)}',
    '${esc(d.Ciudad)}',
    ${d.Score_Cal || 0},
    ${d.Score_Radar || 0},
    ${d.Composite_Score || 0},
    '${esc(d.Es_Multinacional)}',
    '${fecha}'
  )`;
});

const sql = `
INSERT INTO matec_radar.contactos (
  apollo_id, empresa, pais, nombre, apellido, cargo, nivel,
  email_verificado, estado_email, linkedin_url,
  tel_empresa, tel_movil, linea_negocio, tier,
  grupo_empresarial, ciudad,
  score_calificacion, score_radar, composite_score,
  es_multinacional, fecha_prospeccion
) VALUES ${rows.join(',\n')}
ON CONFLICT (apollo_id) DO UPDATE SET
  email_verificado = EXCLUDED.email_verificado,
  estado_email     = EXCLUDED.estado_email,
  linkedin_url     = EXCLUDED.linkedin_url,
  tel_empresa      = EXCLUDED.tel_empresa,
  tel_movil        = EXCLUDED.tel_movil,
  tier             = EXCLUDED.tier,
  score_calificacion = EXCLUDED.score_calificacion,
  score_radar      = EXCLUDED.score_radar,
  composite_score  = EXCLUDED.composite_score,
  fecha_prospeccion= EXCLUDED.fecha_prospeccion
WHERE
  matec_radar.contactos.email_verificado IS DISTINCT FROM EXCLUDED.email_verificado
  OR matec_radar.contactos.tier IS DISTINCT FROM EXCLUDED.tier;
`;

return [{ json: { sql, _row_count: rows.length, _empresa: items[0].json.Empresa } }];

const data = $input.all()[0].json;
return [{ json: {
  Empresa_Dominio: data.company_domain || data.empresa,
  Empresa:         data.empresa,
  Sub_Linea:       data.linea_negocio,
  Pais:            data.pais,
  Dominio:         data.company_domain || '',
  Razon:           'Apollo no devolvió contactos para los job titles configurados',
  Re_escanear:     'Si',
  Fecha:           data.fecha_prospeccion,
  Tier:            data.tier,
  sql: `INSERT INTO matec_radar.sin_contactos (empresa, dominio, sub_linea, pais, razon, re_escanear, fecha, tier) VALUES ('${(data.empresa||'').replace(/'/g,"''")}','${(data.company_domain||'').replace(/'/g,"''")}','${(data.linea_negocio||'').replace(/'/g,"''")}','${(data.pais||'').replace(/'/g,"''")}','Apollo sin resultados para job titles configurados','Si','${data.fecha_prospeccion}','${data.tier}') ON CONFLICT (empresa, pais) DO NOTHING;`
}}];

// Nodo final: query Supabase para traer los contactos recién insertados
// y responder al webhook con la lista completa
// Se ejecuta cuando el loop termina (output 0 = done)
const items = $input.all();
return [{ json: {
  status: 'ok',
  message: 'Prospección completada',
  _loop_done: true,
} }];

// Construir respuesta final para el frontend
const supabaseResp = $input.all()[0].json;
const contactos = Array.isArray(supabaseResp) ? supabaseResp : (supabaseResp.data || supabaseResp.contactos || []);

const nivelOrder = {'C-LEVEL':0,'DIRECTOR':1,'GERENTE':2,'JEFE':3,'ANALISTA':4};
const sorted = [...contactos].sort((a,b) => (nivelOrder[a.nivel]||5) - (nivelOrder[b.nivel]||5));

return [{ json: {
  success: true,
  version: '3.0',
  total: sorted.length,
  con_email: sorted.filter(c => c.email_verificado).length,
  con_linkedin: sorted.filter(c => c.linkedin_url).length,
  contactos: sorted,
  timestamp: new Date().toISOString(),
} }];
